      CREATE OR REPLACE FUNCTION notify_hl7_diagnostic_order_test_submitted()
RETURNS TRIGGER AS $function$
      BEGIN
      INSERT INTO ${hl7.integrationSchema}.hl7_event (
        id,
        event_type,
        object_key,
        event_datetime
      )
      VALUES (
               gen_random_uuid()::varchar,
               '${hl7.events.orderCreated}',
               NEW.id::varchar,
               NOW()
             );

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;

  DROP TRIGGER IF EXISTS trg_hl7_diagnostic_order_test_submitted ON diagnostic_order_tests;

  CREATE TRIGGER trg_hl7_diagnostic_order_test_submitted
    AFTER UPDATE OF status ON diagnostic_order_tests
    FOR EACH ROW
    WHEN (
    NEW.status = 'SUBMITTED'
    AND OLD.status IS DISTINCT FROM NEW.status
)
EXECUTE FUNCTION notify_hl7_diagnostic_order_test_submitted();
